{
  "sentences": [
    {
      "text": "公寓在學校附近。",
      "pinyin": "Gōngyù zài xuéxiào fùjìn.",
      "pinyin_numeric": "gong1yu4 zai4 xue2xiao4 fu4jin4",
      "translation_en": "The apartment is near the school.",
      "translation_ko": "아파트가 학교 근처에 있습니다."
    },
    {
      "text": "客廳在廚房的前面。",
      "pinyin": "Kètīng zài chúfáng de qiánmiàn.",
      "pinyin_numeric": "ke4ting1 zai4 chu2fang2 de qian2mian4",
      "translation_en": "The living room is in front of the kitchen.",
      "translation_ko": "거실이 주방 앞에 있습니다."
    },
    {
      "text": "浴室在房間的旁邊。",
      "pinyin": "Yùshì zài fángjiān de pángbiān.",
      "pinyin_numeric": "yu4shi4 zai4 fang2jian1 de pang2bian1",
      "translation_en": "The bathroom is next to the room.",
      "translation_ko": "욕실이 방 옆에 있습니다."
    },
    {
      "text": "陽台在客廳的外面。",
      "pinyin": "Yángtái zài kètīng de wàimiàn.",
      "pinyin_numeric": "yang2tai2 zai4 ke4ting1 de wai4mian4",
      "translation_en": "The balcony is outside the living room.",
      "translation_ko": "발코니가 거실 밖에 있습니다."
    },
    {
      "text": "冰箱在廚房裡面。",
      "pinyin": "Bīngxiāng zài chúfáng lǐmiàn.",
      "pinyin_numeric": "bing1xiang1 zai4 chu2fang2 li3mian4",
      "translation_en": "The refrigerator is inside the kitchen.",
      "translation_ko": "냉장고가 주방 안에 있습니다."
    },
    {
      "text": "洗衣機在浴室裡面。",
      "pinyin": "Xǐyījī zài yùshì lǐmiàn.",
      "pinyin_numeric": "xi3yi1ji1 zai4 yu4shi4 li3mian4",
      "translation_en": "The washing machine is inside the bathroom.",
      "translation_ko": "세탁기가 욕실 안에 있습니다."
    },
    {
      "text": "書桌在窗戶的旁邊。",
      "pinyin": "Shūzhuō zài chuānghù de pángbiān.",
      "pinyin_numeric": "shu1zhuo1 zai4 chuang1hu4 de pang2bian1",
      "translation_en": "The desk is next to the window.",
      "translation_ko": "책상이 창문 옆에 있습니다."
    },
    {
      "text": "沙發在客廳的中間。",
      "pinyin": "Shāfā zài kètīng de zhōngjiān.",
      "pinyin_numeric": "sha1fa1 zai4 ke4ting1 de zhong1jian1",
      "translation_en": "The sofa is in the middle of the living room.",
      "translation_ko": "소파가 거실 중간에 있습니다."
    },
    {
      "text": "衣櫃在床的後面。",
      "pinyin": "Yīguì zài chuáng de hòumiàn.",
      "pinyin_numeric": "yi1gui4 zai4 chuang2 de hou4mian4",
      "translation_en": "The wardrobe is behind the bed.",
      "translation_ko": "옷장이 침대 뒤에 있습니다."
    },
    {
      "text": "冷氣在客廳的牆壁上。",
      "pinyin": "Lěngqì zài kètīng de qiángbì shàng.",
      "pinyin_numeric": "leng3qi4 zai4 ke4ting1 de qiang2bi4 shang4",
      "translation_en": "The air conditioner is on the wall of the living room.",
      "translation_ko": "에어컨이 거실 벽 위에 있습니다."
    }
  ]
}
